<body>
<div class="clock-wrapper">
  <div class="clock-face">
    <canvas id="clockCanvas" width="640" height="640"></canvas>
  </div>
  <div class="info-panel">
    <span class="time-text" id="digitalTime">--:--:--</span>
    <span class="date-text" id="digitalDate">----年--月--日</span>
  </div>
