      // 构建三列HTML
      let html = '';
      for (const status of STATUSES) {
        const columnTasks = filtered.filter(t => t.status === status);
        // 按创建时间排序（新的在前）
        columnTasks.sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));

