</div>

<script>
  (function() {
    // ----- 1. generate scale marks (60) -----
    const scaleContainer = document.getElementById('scaleContainer');
    for (let i = 0; i < 60; i++) {
      const mark = document.createElement('div');
      mark.className = 'scale-mark';
      if (i % 5 === 0) {
        mark.classList.add('hour-mark');   // thicker, darker (every hour)
      }
      // rotate each mark around center
      const angle = i * 6;  // 360/60
      mark.style.transform = `rotate(${angle}deg)`;
      scaleContainer.appendChild(mark);
    }

    // ----- 2. generate numbers 1..12 (placed at hour positions) -----
    const numbersContainer = document.getElementById('clockNumbers');
    const numberRadius = 0.82; // relative to half size (82% from center)
    for (let i = 1; i <= 12; i++) {
      const numDiv = document.createElement('div');
      numDiv.className = 'clock-number';
      // angle: 12 at 0°, 1 at 30°, etc. (clockwise)
      const angleDeg = i * 30;
      const rad = (angleDeg - 90) * Math.PI / 180;  // -90 because 0° = top (12)
      // use parent size – we'll set position later via CSS, but we compute using % 
      // easier: position using percentage from center
      const xPercent = 50 + numberRadius * 50 * Math.cos(rad);
      const yPercent = 50 + numberRadius * 50 * Math.sin(rad);
      numDiv.style.left = xPercent + '%';
      numDiv.style.top = yPercent + '%';
      numDiv.textContent = i;
      numbersContainer.appendChild(numDiv);
    }

    // ----- 3. clock update logic (Beijing Time UTC+8) -----
    const hourHand = document.getElementById('hourHand');
    const minuteHand = document.getElementById('minuteHand');
    const secondHand = document.getElementById('secondHand');
    const timeDisplay = document.getElementById('timeDisplay');
    const dateDisplay = document.getElementById('dateDisplay');

    // helper to parse beijing time (UTC+8) 
    function getBeijingTime() {
      // use toLocaleString to get reliable Asia/Shanghai time string
      const timeStr = new Date().toLocaleString('en-US', { timeZone: 'Asia/Shanghai' });
      // format: "M/D/YYYY, HH:MM:SS AM/PM" — parse carefully
      // example: "4/8/2025, 2:35:19 PM"
      const [datePart, timePart] = timeStr.split(', ');
      const [month, day, year] = datePart.split('/').map(Number);
      let [hourStr, minuteStr, secondStr] = timePart.split(':');
      let hour = parseInt(hourStr, 10);
      const minute = parseInt(minuteStr, 10);
      const second = parseInt(secondStr, 10);
      const ampm = timePart.includes('PM') ? 'PM' : 'AM';

      // correct hour for 12h format
      if (ampm === 'PM' && hour !== 12) hour += 12;
      if (ampm === 'AM' && hour === 12) hour = 0;

      // also get weekday & date string
      const beijingDate = new Date(year, month - 1, day, hour, minute, second);
      // produce date display: "2025年4月8日 周二" (or similar)
      // we need day of week (中文 或英文简短)
      const weekdays = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
      const weekdayIndex = beijingDate.getDay();
      const weekdayStr = weekdays[weekdayIndex];
      const dateStr = `${year}年${month}月${day}日 ${weekdayStr}`;

      // time text (24h format with leading zeros)
      const hourStr24 = String(hour).padStart(2, '0');
      const minuteStr24 = String(minute).padStart(2, '0');
      const secondStr24 = String(second).padStart(2, '0');
      const timeText = `${hourStr24}:${minuteStr24}:${secondStr24}`;

      return { hour, minute, second, timeText, dateStr };
    }

    // smooth second angle: sub‑second precision using Date.now()
    function getSmoothSecond() {
      const now = new Date();
      // but we need beijing time offset: UTC+8
      const utcMs = now.getTime() + now.getTimezoneOffset() * 60000; // UTC ms
      const beijingMs = utcMs + 8 * 3600000; // UTC+8
      // total seconds (including milliseconds as fraction)
      const totalSec = (beijingMs % 86400000) / 1000;
      const secondFraction = totalSec % 60;  // e.g., 45.732
      return secondFraction;
    }

    function updateClock() {
      // beijing time (rounded to current second for hour/minute)
      const bj = getBeijingTime();
      const { hour, minute, second, timeText, dateStr } = bj;

      // smooth second angle (continuous)
      const smoothSec = getSmoothSecond();   // float (0.0 .. 60.0)
      const secondAngle = smoothSec * 6;      // 360/60

      // minute hand angle: includes fractional minute from smoothSecond
      const minuteFloat = minute + smoothSec / 60;
      const minuteAngle = minuteFloat * 6;     // 360/60

      // hour hand angle: 12 hours = 360°, plus minute influence
      const hourFloat = (hour % 12) + minuteFloat / 60;
      const hourAngle = hourFloat * 30;        // 360/12

      // apply rotations (with transition removed for smooth second hand)
      secondHand.style.transform = `rotate(${secondAngle}deg)`;
      minuteHand.style.transform = `rotate(${minuteAngle}deg)`;
      hourHand.style.transform = `rotate(${hourAngle}deg)`;

      // update text displays
      timeDisplay.textContent = timeText;
      dateDisplay.textContent = dateStr;
    }

    // initial call
    updateClock();

    // use requestAnimationFrame for silky smooth second hand (60fps)
    let rafId = null;
    function tick() {
      updateClock();
      rafId = requestAnimationFrame(tick);
    }
    rafId = requestAnimationFrame(tick);

    // fallback: also run setInterval to avoid rare stalls (but raf is sufficient)
    // we keep a backup interval (less frequent)
    const backupInterval = setInterval(() => {
      if (document.hidden) {
        // when tab hidden, raf may slow; update anyway
        updateClock();
      }
    }, 250);

    // clean up on page unload (optional)
    window.addEventListener('beforeunload', () => {
      if (rafId) cancelAnimationFrame(rafId);
      clearInterval(backupInterval);
    });

  })();
</script>
