        else:
            rejected.append({
                'id': session.get('id', 'unknown'),
                'reason': reason
            })

    max_value, selected_ids = weighted_interval_scheduling(valid_sessions)

    result = {
        'max_value': max_value,
        'selected_ids': selected_ids,
        'rejected': rejected
    }

