                "selected_ids": ["good"],
                "rejected": [
                    {"id": "bad_end", "reason": "end must be after start"},
                    {"id": "neg_val", "reason": "value must be non-negative"},
                    {"id": "missing_field", "reason": "missing required field"}
                ]
