        }
        /* 空状态 */
        .empty-tip {
            color: #94a3b8;
            text-align: center;
            padding: 1.2rem 0;
            font-size: 0.9rem;
        }
        /* 响应式：窄屏三列纵向 */
        @media (max-width: 720px) {
            .board {
                grid-template-columns: 1fr;
            }
            .toolbar {
                flex-direction: column;
                align-items: stretch;
            }
            .toolbar h1 { margin-right: 0; }
        }
        @media (max-width: 480px) {
