                addBtn._handler = addNoteHandler;
            };
            addBtn.removeEventListener('click', addNoteHandler);
            addBtn.addEventListener('click', handler);
            addBtn._handler = handler;
        }

        function addNoteHandler() { addNote(); }

        // ---------- init ----------
