                fish.vx += steerX;
                fish.vy += steerY;

                // limit speed
                const speed = Math.hypot(fish.vx, fish.vy);
                if (speed > MAX_SPEED) {
                    fish.vx = (fish.vx / speed) * MAX_SPEED;
                    fish.vy = (fish.vy / speed) * MAX_SPEED;
