                ctx.fillStyle = '#141414';
                ctx.fill();
                ctx.beginPath();
                ctx.arc(l/4 + 2.5, -h/6 - 1.2, 0.9, 0, Math.PI*2);
                ctx.fillStyle = 'white';
                ctx.fill();

                ctx.restore();
            }

            // bubble decoration
