<div class="toolbar">
    <h1>📋 看板</h1>
    <div class="search-box">
        <input type="text" id="searchInput" placeholder="搜索标题、备注…" aria-label="搜索任务">
        <select id="priorityFilter" aria-label="筛选优先级">
