            position: absolute;
            inset: 12px;
            border-radius: 50%;
        }

        .scale {
            position: absolute;
            top: 0;
            left: 50%;
            width: 2px;
            height: 100%;
            transform-origin: center center;
            transform: translateX(-50%) rotate(var(--rot));
        }

        .scale::before {
            content: '';
            display: block;
            position: absolute;
            top: 6px;              /* distance from rim */
            left: 50%;
            transform: translateX(-50%);
            width: 2px;
            height: 10px;
            background: #8b9bb0;
            border-radius: 1px;
        }

        /* thick hour scales (every 5th = 12 positions) */
        .scale.hour-scale::before {
            width: 3px;
            height: 18px;
            background: #2a384b;
            box-shadow: 0 0 0 0.5px rgba(255,255,255,0.3);
            top: 4px;
        }

        /* numbers (12,3,6,9) */
